import React, { useState, useEffect, useMemo } from 'react';


const Icon = ({ name }) => {
  const icons = {
    telegram: (
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>
    ),
    phone: (
      <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
    )
  };

  return (
    <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
      {icons[name]}
    </svg>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];

  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800" },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800" },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800" },
    ],
    archive: [
      { id: 'a1', title: "Учебный логотип", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800" },
      { id: 'a2', title: "Графическая работа", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1561070791-2526d30994b5?auto=format&fit=crop&q=80&w=800" },
      { id: 'a3', title: "Макет полиграфии", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1586075010923-2dd4570fb338?auto=format&fit=crop&q=80&w=800" },
      { id: 'a4', title: "Первый лендинг", cat: "Веб-дизайн", year: 2024, img: "https://images.unsplash.com/photo-1547658719-da2b51169166?auto=format&fit=crop&q=80&w=800" },
    ]
  }), []);

  const filterFn = (p) => filter === 'Все' || p.cat === filter;
  const filteredFeatured = projects.featured.filter(filterFn);
  const filteredArchive = projects.archive.filter(filterFn);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) {
      const offset = 140; // Учитываем высоту липкой шапки
      const bodyRect = document.body.getBoundingClientRect().top;
      const elementRect = el.getBoundingClientRect().top;
      const elementPosition = elementRect - bodyRect;
      const offsetPosition = elementPosition - offset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
    }
  };

  return (
    <div className="min-h-screen bg-[#0d0d0f] text-[#e0e0e6] font-sans selection:bg-[#ffb3d9] selection:text-[#2d1b24]">

      {/* Header & Filters (Glassmorphism) */}
      <div className="fixed top-0 w-full z-50 flex flex-col">
        <header className={`px-6 md:px-12 py-5 bg-[#0d0d0f]/80 backdrop-blur-xl border-b border-white/5 transition-all duration-300 ${isScrolled ? 'py-4' : 'py-6'}`}>
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <div className="text-lg font-bold tracking-[0.2em] text-[#ffb3d9] uppercase font-sans">
              АЛЕКСАНДРА БЛАГОДАТСКИХ
            </div>

            {/* Навигация */}
            <nav className="hidden md:flex items-center gap-8 text-[10px] uppercase tracking-[0.2em] text-white/40">
              <button onClick={() => scrollTo('projects')} className="hover:text-white transition-colors">Проекты</button>
              <button onClick={() => scrollTo('about')} className="hover:text-white transition-colors">Обо мне</button>
              <button onClick={() => scrollTo('contact')} className="hover:text-white transition-colors">Контакты</button>
            </nav>

            <div className="flex gap-5 items-center">
              <a href="https://t.me/renraie" target="_blank" className="hover:text-[#ffb3d9] transition-all transform hover:scale-110">
                <Icon name="telegram"/>
              </a>
              <a href="tel:+79639960003" className="hover:text-[#ffb3d9] transition-all transform hover:scale-110">
                <Icon name="phone"/>
              </a>
            </div>
          </div>
        </header>

        <div className="px-6 md:px-12 py-4 bg-[#0d0d0f]/60 backdrop-blur-lg border-b border-white/5">
          <div className="max-w-7xl mx-auto flex flex-wrap gap-2">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-1.5 rounded-full text-[10px] uppercase tracking-wider transition-all border font-sans ${
                  filter === cat 
                  ? 'bg-[#ffb3d9] border-[#ffb3d9] text-[#2d1b24]' 
                  : 'bg-white/5 border-white/10 text-white/40 hover:border-white/20'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Hero / About Section */}
      <section id="about" className="pt-72 pb-24 px-6 md:px-12">
        <div className="max-w-7xl mx-auto">
          <h1 className="text-5xl md:text-[6.5rem] font-serif font-light tracking-tight mb-8 leading-[1.05] max-w-4xl text-white">
            Учусь делать <span className="italic text-[#ffb3d9]">красивый</span> и понятный дизайн.
          </h1>
          <p className="max-w-2xl text-white/40 text-xl font-sans font-light leading-relaxed">
            Привет, я Александра. Изучаю айдентику, логотипы и веб-дизайн. 
            Здесь я собираю свои работы — от первых шагов в печатной графике до текущих учебных кейсов.
          </p>
        </div>
      </section>

      {/* Projects Section */}
      <main id="projects" className="max-w-7xl mx-auto px-6 md:px-12 pb-32">
        <div className="mb-24">
          <h2 className="text-[10px] uppercase tracking-[0.4em] text-white/20 mb-10 font-sans">Избранные проекты</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
            {filteredFeatured.map((project) => (
              <div key={project.id} className="group cursor-pointer">
                <div className="relative rounded-[2rem] overflow-hidden aspect-[4/3] bg-white/5 mb-6 border border-white/5 shadow-2xl transition-all duration-500 group-hover:border-[#ffb3d9]/30">
                  <img src={project.img} alt={project.title} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105" />
                  <div className="absolute inset-0 bg-gradient-to-t from-[#0d0d0f]/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
                </div>
                <div className="flex justify-between items-end px-2">
                  <div>
                    <h3 className="text-xl font-medium mb-1 group-hover:text-[#ffb3d9] transition-colors font-sans">{project.title}</h3>
                    <p className="text-[10px] uppercase tracking-widest text-white/30 font-sans">{project.cat}</p>
                  </div>
                  <span className="text-[10px] text-white/10 font-sans">{project.year}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="pt-10 border-t border-white/5 text-center md:text-left">
          <button 
              onClick={() => setShowArchive(!showArchive)}
              className="px-8 py-3 bg-white/5 hover:bg-[#ffb3d9]/10 border border-white/10 hover:border-[#ffb3d9]/30 rounded-full text-[10px] uppercase tracking-[0.4em] text-white/40 hover:text-[#ffb3d9] transition-all duration-500 font-sans"
          >
            {showArchive ? '— Свернуть' : '+ Показать архив'}
          </button>

          {showArchive && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mt-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
              {filteredArchive.map((project) => (
                <div key={project.id} className="group">
                  <div className="relative rounded-2xl overflow-hidden aspect-square bg-white/5 mb-4 border border-white/5 transition-all group-hover:border-white/20">
                      <img src={project.img} alt={project.title} className="w-full h-full object-cover opacity-40 group-hover:opacity-100 transition-opacity duration-500" />
                  </div>
                  <h4 className="text-sm font-medium text-white/60 mb-1 font-sans">{project.title}</h4>
                  <p className="text-[9px] uppercase tracking-widest text-white/20 font-sans">{project.cat}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {/* Footer / Contact Section */}
      <footer id="contact" className="py-24 px-6 md:px-12 bg-[#0d0d0f] border-t border-white/5">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-end gap-16">
          <div>
            <h2 className="text-4xl font-serif mb-12 italic text-[#ffb3d9]">Связаться со мной</h2>
            <div className="flex flex-col gap-6 font-sans">
              <a href="tel:+79639960003" className="text-2xl font-light hover:text-[#ffb3d9] transition-all border-b border-white/5 pb-2 inline-block">8 (963) 996-00-03</a>
              <a href="https://t.me/renraie" target="_blank" className="text-2xl font-light hover:text-[#ffb3d9] transition-all border-b border-white/5 pb-2 inline-block">Telegram: @renraie</a>
            </div>
          </div>
          <div className="text-[10px] uppercase tracking-[0.4em] text-white/10 font-sans">
            © 2024—2026 Alexandra Blagodatskikh
          </div>
        </div>
      </footer>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap');

        body { 
          font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
          background-color: #0d0d0f;
          -webkit-font-smoothing: antialiased;
        }

        .font-serif {
          font-family: 'Playfair Display', serif;
        }

        html { scroll-behavior: smooth; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: #0d0d0f; }
        ::-webkit-scrollbar-thumb { background: rgba(255, 179, 217, 0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;
